package me.kright.gametools.pga2d

import scala.annotation.targetName
import me.kright.gametools.mathutil.FlatDoubleSerializer


/**
 * A motor: a rigid transformation of the 2d plane (combined rotation and translation),
 * the even-graded (0, 2) element of 2d PGA. Applied with motor.sandwich(obj).
 * A motor is the exponent of a grade-2 element (projectivePoint.exp()), and motor.log() returns that element back.
 *
 * Variable fields: s, wx, wy, xy.
 *
 * Generated by pgaNdCodeGen (me.kright.gametools.pga.codegen.scala.pga2d.runScalaCodeGen).
 * Do not edit by hand: change the generator and re-run it.
 */
final case class Pga2dMotor(s: Double = 0.0,
                            wx: Double = 0.0,
                            wy: Double = 0.0,
                            xy: Double = 0.0) derives CanEqual, FlatDoubleSerializer:

  override def toString: String =
    s"Pga2dMotor(s = $s, wx = $wx, wy = $wy, xy = $xy)"

  def dual: Pga2dMultivector =
    Pga2dMultivector(
      s = 0.0,
      w = xy,
      x = -wy,
      y = wx,
      wx = 0.0,
      wy = 0.0,
      xy = 0.0,
      i = s,
    )

  def weight: Pga2dVector =
    Pga2dVector(
      x = -wy,
      y = wx,
    )

  def bulk: Pga2dRotor =
    Pga2dRotor(
      s = s,
      xy = xy,
    )

  @targetName("unaryMinus")
  def unary_- : Pga2dMotor =
    Pga2dMotor(
      s = -s,
      wx = -wx,
      wy = -wy,
      xy = -xy,
    )

  def reverse: Pga2dMotor =
    Pga2dMotor(
      s = s,
      wx = -wx,
      wy = -wy,
      xy = -xy,
    )

  def antiReverse: Pga2dMotor =
    Pga2dMotor(
      s = -s,
      wx = wx,
      wy = wy,
      xy = xy,
    )

  /**
   * 2D motors satisfy m * reverse(m) = scalar exactly, so renormalization is a uniform scale
   */
  def renormalized: Pga2dMotor =
    val a = 1.0 / Math.sqrt(s * s + xy * xy)
    Pga2dMotor(
      s = a * s,
      wx = a * wx,
      wy = a * wy,
      xy = a * xy,
    )

  /** motor has to be normalized */
  def toRotorAndTranslator: (Pga2dRotor, Pga2dTranslator) = {
    val q = this.toRotorUnsafe
    val t = q.reverse.geometric(this)
    (q, t.toTranslatorUnsafe)
  }

  /** motor has to be normalized */
  def toTranslatorAndRotor: (Pga2dTranslator, Pga2dRotor) = {
    val q = this.toRotorUnsafe
    val t = this.geometric(q.reverse)
    (t.toTranslatorUnsafe, q)
  }

  def bulkNormSquare: Double =
    (s * s + xy * xy)

  def bulkNorm: Double =
    Math.sqrt(bulkNormSquare)

  def normalizedByBulk =
    this / bulkNorm

  def weightNormSquare: Double =
    (wx * wx + wy * wy)

  def weightNorm: Double =
    Math.sqrt(weightNormSquare)

  def normalizedByWeight =
    this / weightNorm

  def normSquare: Double =
    (s * s + wx * wx + wy * wy + xy * xy)

  def norm: Double =
    Math.sqrt(normSquare)

  def normalizedByNorm =
    this / norm

  @targetName("times")
  def *(v: Double): Pga2dMotor =
    Pga2dMotor(
      s = s * v,
      wx = v * wx,
      wy = v * wy,
      xy = v * xy,
    )

  @targetName("div")
  def /(v: Double): Pga2dMotor =
    this * (1.0 / v)

  @targetName("plus")
  def +(v: Pga2dMotor): Pga2dMotor =
    Pga2dMotor(
      s = (s + v.s),
      wx = (v.wx + wx),
      wy = (v.wy + wy),
      xy = (v.xy + xy),
    )

  @targetName("minus")
  def -(v: Pga2dMotor): Pga2dMotor =
    Pga2dMotor(
      s = (s - v.s),
      wx = (wx - v.wx),
      wy = (wy - v.wy),
      xy = (xy - v.xy),
    )

  def madd(v: Pga2dMotor, mult: Double): Pga2dMotor =
    Pga2dMotor(
      s = (s + mult * v.s),
      wx = (wx + mult * v.wx),
      wy = (wy + mult * v.wy),
      xy = (xy + mult * v.xy),
    )

  def multiplyElementwise(v: Pga2dMotor): Pga2dMotor =
    Pga2dMotor(
      s = s * v.s,
      wx = v.wx * wx,
      wy = v.wy * wy,
      xy = v.xy * xy,
    )

  def log(): Pga2dProjectivePoint =
    val scalar = s
    if (s < 0.0) return (-this).log()

    val lenXY = Math.abs(xy)
    val angle = Math.atan2(lenXY, scalar)

    // 1 / sin^2 for a normalized motor; (1.0 - scalar * scalar) is the same value,
    // but cancels catastrophically for small angles (relative error ~eps / angle^2)
    val a = 1.0 / (lenXY * lenXY)

    val b = if (Math.abs(angle) > 1e-5) { // angle / sin(angle)
      angle * Math.sqrt(a)
    } else {
      // x/sin(x) = 1 + x^2/6 + 7x^4/360 + ...; at x <= 1e-5 the dropped 7x^4/360 <= 2e-22
      // relative term is far below 2^-53, so the second-order form is exact in double
      1.0 + angle * angle / 6.0
    }

    Pga2dProjectivePoint(
      x = -b * wy,
      y = b * wx,
      w = b * xy,
    )

  /**
   * Spherical linear interpolation along the geodesic from this (t = 0) to b (t = 1),
   * with constant angular velocity. Computes this * (this.reverse.geometric(b))^t via log/exp.
   * Assumes both this and b are normalized; the result is normalized.
   * Near-antipodal inputs (b close to -this) are ill-conditioned: the geodesic is undefined
   * there and the interpolation direction becomes numerically unstable.
   */
  def slerp(b: Pga2dMotor, t: Double): Pga2dMotor =
    this.geometric(this.reverse.geometric(b).log().exp(t))

  /**
   * Normalized linear interpolation: the componentwise lerp this * (1 - t) + b * t, renormalized.
   * A fast APPROXIMATION of slerp: the angular velocity is not constant, so intermediate values
   * deviate from the true geodesic. The error is negligible for small angles between this and b
   * and grows toward the midpoint of large rotations. Assumes both inputs are normalized.
   */
  def nlerp(b: Pga2dMotor, t: Double): Pga2dMotor =
    (this * (1.0 - t) + b * t).renormalized

  def toMultivector: Pga2dMultivector =
    Pga2dMultivector(
      s = s,
      w = 0.0,
      x = 0.0,
      y = 0.0,
      wx = wx,
      wy = wy,
      xy = xy,
      i = 0.0,
    )

  def toProjectivePointUnsafe: Pga2dProjectivePoint =
    Pga2dProjectivePoint(
      x = -wy,
      y = wx,
      w = xy,
    )

  def toRotorUnsafe: Pga2dRotor =
    Pga2dRotor(
      s = s,
      xy = xy,
    )

  def toProjectiveTranslatorUnsafe: Pga2dProjectiveTranslator =
