      wx = wx,
      wy = wy,
    )

  def toTranslatorUnsafe: Pga2dTranslator =
    Pga2dTranslator(
      wx = wx,
      wy = wy,
    )

  def toVectorUnsafe: Pga2dVector =
    Pga2dVector(
