    Pga2dMotor(
      s = (s * v.s - v.xy * xy),
      wx = (s * v.wx + v.s * wx + v.wy * xy - v.xy * wy),
      wy = (s * v.wy + v.s * wy + v.xy * wx - v.wx * xy),
      xy = (s * v.xy + v.s * xy),
    )

  infix def geometric(v: Pga2dLine): Pga2dMultivector =
    Pga2dMultivector(
      s = 0.0,
      w = (s * v.w + v.x * wx + v.y * wy),
      x = (s * v.x + v.y * xy),
      y = (s * v.y - v.x * xy),
      wx = 0.0,
      wy = 0.0,
      xy = 0.0,
      i = (v.w * xy + v.y * wx - v.x * wy),
    )

  infix def geometric(v: Pga2dProjectivePoint): Pga2dMotor =
    Pga2dMotor(
      s = -v.w * xy,
      wx = (s * v.y - v.w * wy - v.x * xy),
